import { writable } from 'svelte/store';

const EMPTY_NEXT_STEP_HINT = {
	row: null,
	col: null,
	value: null,
};

function createNextStepHint() {
	const hint = writable({ ...EMPTY_NEXT_STEP_HINT });

	return {
		subscribe: hint.subscribe,

		show(result) {
			if (!result.ok) {
				this.clear();
				return;
			}

			hint.set({
				row: result.row,
				col: result.col,
				value: result.value,
			});
		},

		clear() {
			hint.set({ ...EMPTY_NEXT_STEP_HINT });
		},
	};
}

// 功能：标记最近一次由“下一步提示”写入的格子，用于 UI 特殊颜色显示。
export const nextStepHint = createNextStepHint();
